from auth import TokenStore


class SessionService:
    def __init__(self, store: TokenStore):
        self.store = store

    def login(self, user_id: int) -> str:
        return self.store.issue(user_id)

    def refresh(self, old_token: str) -> str:
        new, user_id = self.store.rotate(old_token)
        return new

    def logout(self, token: str) -> bool:
        return self.store.revoke(token)
